package api

import (
	"regexp"
	"time"
)

// validBookingID matches IDs generated by the app:
//   - "booking-<digits>" (user-created)
//   - "kueue-<namespace>-<resource>-s<digit>-<date>" (kueue-synced)
var validBookingID = regexp.MustCompile(`^(booking-\d+|kueue-[a-z0-9-]+-[a-z0-9]+-s\d+-\d{4}-\d{2}-\d{2})$`)

// IsValidBookingID checks that an ID matches the expected format.
func IsValidBookingID(id string) bool {
	return len(id) <= 256 && validBookingID.MatchString(id)
}

// IsValidBookingDate checks that a date string is valid and within the booking window.
func IsValidBookingDate(dateStr string, windowDays int) bool {
	d, err := time.Parse("2006-01-02", dateStr)
	if err != nil {
		return false
	}
	today := time.Now().Truncate(24 * time.Hour)
	maxDate := today.AddDate(0, 0, windowDays+1)
	return !d.Before(today) && d.Before(maxDate)
}
